(self.webpackChunkdemo=self.webpackChunkdemo||[]).push([[3216],{3216:n=>{n.exports='<label tuiInputFiles="l">\n    <input\n        tuiInputFiles\n        [formControl]="control"\n    />\n    <ng-template let-dragged>\n        <ng-container *ngIf="dragged; else base">\n            <tui-avatar\n                appearance="secondary"\n                src="@tui.droplet"\n            />\n            <div>\n                Drop it like it\'s hot!\n                <br />\n                <br />\n            </div>\n        </ng-container>\n\n        <ng-template #base>\n            <tui-avatar\n                appearance="secondary"\n                src="@tui.cloud-upload"\n            />\n            <div>\n                Drag and drop file here or\n                <a tuiLink>click to upload</a>\n            </div>\n            <div class="types">PNG, JPG, JPEG, PNG, etc</div>\n        </ng-template>\n    </ng-template>\n</label>\n\n<tui-files class="tui-space_top-4">\n    <tui-file\n        [file]="file"\n        [leftContent]="content"\n    >\n        <span class="tui-text_body-s-2">file is on checking</span>\n    </tui-file>\n</tui-files>\n\n<ng-template #content>\n    <tui-icon icon="@tui.clock" />\n</ng-template>\n'}}]);